import React from "react";

const Input = ({ value, onChange, onKeyDown, placeholder }) => {
    return (
        <input
            type="text"
            placeholder={placeholder}
            value={value}
            onChange={onChange}
            onKeyDown={onKeyDown}
            autoComplete="off"
        />
    );
};

export default Input;
